namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = new();
    public List<string> Steps { get; set; } = new();
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Ingredients = new() { "Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt" },
            Steps = new() { "Preheat oven to 475°F (245°C).", "Roll out dough on floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute.", "Bake for 10-12 minutes.", "Top with fresh basil and drizzle olive oil." },
            AverageRating = 4.5, RatingCount = 12
        },
        new Recipe
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Ingredients = new() { "Spaghetti", "Guanciale", "Egg yolks", "Pecorino Romano", "Black pepper" },
            Steps = new() { "Cook spaghetti in salted water.", "Crisp guanciale in a pan.", "Whisk egg yolks with grated pecorino.", "Toss hot pasta with guanciale.", "Remove from heat and stir in egg mixture.", "Season with black pepper and serve." },
            AverageRating = 4.8, RatingCount = 20
        },
        new Recipe
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Ingredients = new() { "Chicken thighs", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger" },
            Steps = new() { "Marinate chicken in yogurt and spices for 2 hours.", "Grill or broil chicken until charred.", "Sauté onions, garlic, and ginger.", "Add tomato sauce and simmer.", "Stir in cream and spices.", "Add chicken pieces and simmer 10 minutes." },
            AverageRating = 4.6, RatingCount = 15
        },
        new Recipe
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
            Ingredients = new() { "Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Sugar" },
            Steps = new() { "Soak rice noodles in warm water.", "Press and cube tofu, then pan-fry.", "Make sauce with tamarind, fish sauce, and sugar.", "Stir-fry noodles with sauce.", "Add tofu and bean sprouts.", "Serve with crushed peanuts and lime." },
            AverageRating = 4.3, RatingCount = 8
        },
        new Recipe
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Ingredients = new() { "Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning" },
            Steps = new() { "Brown ground beef in a skillet.", "Add taco seasoning and water, simmer.", "Warm taco shells in oven.", "Shred lettuce and dice tomatoes.", "Assemble tacos with meat and toppings.", "Serve with sour cream." },
            AverageRating = 4.1, RatingCount = 10
        },
        new Recipe
        {
            Id = 6, Title = "Miso Ramen", Category = "Japanese",
            Ingredients = new() { "Ramen noodles", "Miso paste", "Pork belly", "Soft-boiled egg", "Green onions", "Nori", "Chicken broth" },
            Steps = new() { "Simmer chicken broth with miso paste.", "Cook and slice pork belly.", "Boil ramen noodles.", "Prepare soft-boiled eggs.", "Assemble bowls with broth and noodles.", "Top with pork, egg, nori, and green onions." },
            AverageRating = 4.7, RatingCount = 18
        }
    };

    private int _nextId = 7;

    public List<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public List<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            var totalStars = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
        }
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            AverageRating = 0,
            RatingCount = 0
        };
        _recipes.Add(recipe);
    }
}

