arguments.file_text:
@page "/recipes/{Category}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@inject RecipeService RecipeService

<PageTitle>@Category Recipes</PageTitle>

<h1>@Category Recipes</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

@if (recipes.Any())
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span class="text-muted">No ratings yet</span>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p class="text-muted">No recipes found in this category.</p>
}

@code {
    [Parameter] public string Category { get; set; } = string.Empty;
    private List<Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetRecipesByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <p class="text-danger">Recipe not found.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/recipes/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <div class="row mt-3">
        <div class="col-md-4">
            <h3>Ingredients</h3>
            <ul class="list-group">
                @foreach (var ingredient in recipe.Ingredients)
                {
                    <li class="list-group-item">@ingredient</li>
                }
            </ul>
        </div>
        <div class="col-md-8">
            <h3>Steps</h3>
            <ol class="list-group list-group-numbered">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="mt-4 p-3 border rounded">
        <h4>Rate this Recipe</h4>
        <RecipeCommunity.Client.Pages.StarRating RecipeId="Id" />
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@rendermode InteractiveServer
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>📝 Submit a Recipe</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted successfully!</h4>
        <p>Thank you for sharing your recipe with the community.</p>
        <a href="/" class="btn btn-primary">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="submission.Title" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="submission.Category">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Thai">Thai</option>
                <option value="Mexican">Mexican</option>
                <option value="Japanese">Japanese</option>
                <option value="American">American</option>
                <option value="French">French</option>
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="submission.Ingredients"
                placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="submission.Steps"
                placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
        </div>

        <button type="submit" class="btn btn-success"
            disabled="@(string.IsNullOrWhiteSpace(submission.Title) || string.IsNullOrWhiteSpace(submission.Category))">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    private RecipeSubmission submission = new();
    private bool submitted = false;

    private void HandleSubmit()
    {
        if (!string.IsNullOrWhiteSpace(submission.Title) &&
            !string.IsNullOrWhiteSpace(submission.Category) &&
            !string.IsNullOrWhiteSpace(submission.Ingredients) &&
            !string.IsNullOrWhiteSpace(submission.Steps))
        {
            RecipeService.AddRecipe(submission);
            submitted = true;
        }
    }
}

