@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (hoverRating > 0 ? hoverRating : selectedRating) ? "filled" : "")"
              @onclick="() => Rate(star)"
              @onmouseover="() => hoverRating = star"
              @onmouseout="() => hoverRating = 0"
              role="button"
              aria-label="@star stars">
            ★
        </span>
    }
    @if (selectedRating > 0)
    {
        <span class="ms-2 text-success">You rated @selectedRating star@(selectedRating > 1 ? "s" : "")!</span>
    }
    else
    {
        <span class="ms-2 text-muted">Click to rate</span>
    }
</div>

<style>
    .star-rating .star {
        font-size: 1.8rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.15s;
    }
    .star-rating .star.filled {
        color: #ffc107;
    }
    .star-rating .star:hover {
        color: #ffdb4d;
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int selectedRating = 0;
    private int hoverRating = 0;

    private void Rate(int stars)
    {
        selectedRating = stars;
    }
}

